// Solution
function validateRouteParams(req, next) {
    if (req.method === 'GET' || req.method === 'POST') {
        const id = req.params.id;
        const name = req.params.name;
        if (id > 1000 || !/^[0-9]+$/.test(id)) {
            return next({
                status: 400,
                error: 'Invalid id parameter'
            });
        } else if (name && !/^[a-zA-Z_]+$/.test(name)) {
            return next({
                status: 400,
                error: 'Invalid name parameter'
            });
        } else {
            next();
        }
    } else {
        next();
    }
}

app.use('/users/:id', validateRouteParams);
app.use('/users/:name', validateRouteParams);
